const raw = $input.first().json;

// When called as sub-workflow, n8n passes the parent webhook item
// which wraps the original POST body under raw.body
const data = raw.body || raw;

try {
  let message = null;
  let session_id = null;

  // WhatsApp Cloud API format
  if (data.object === 'whatsapp_business_account') {
    const msg = data.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
    const contact = data.entry?.[0]?.changes?.[0]?.value?.contacts?.[0];
    if (!msg) throw new Error('WhatsApp payload missing message');
    message = msg.text?.body?.trim() || msg.interactive?.button_reply?.title || null;
    session_id = contact?.wa_id || msg.from || null;
  }
  // Chat / webhook format
  else if (data.message && data.session_id) {
    message = String(data.message).trim();
    session_id = String(data.session_id).trim();
  }
  else {
    throw new Error('Unrecognized payload: missing message or session_id');
  }

  if (!message) throw new Error('Empty message after normalization');
  if (!session_id) throw new Error('Missing session_id after normalization');

  return [{ json: { status: 'success', result: { message, session_id }, error: null } }];

} catch (err) {
  return [{ json: { status: 'error', result: {}, error: err.message } }];
}
